import java.util.*;
import sailpoint.object.QueryOptions;
import sailpoint.object.Filter;;
import sailpoint.tools.Util;
import java.text.SimpleDateFormat;


if(args.get("startDate") != null @and args.get("endDate") != null)

Date startDate = args.get("startDate");
String startDateString = Util.dateToString(startDate,"yyyy-MM-dd");

Date endDate = args.get("endDate");
String endDateString = Util.dateToString(endDate,"yyyy-MM-dd");


SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd");
Date startDate = sdf.parse(startDateString);
Date endDate = sdf.parse(endDateString);

// Convert to long 
long startMillis = startDate.getTime();
long endMillis = endDate.getTime();

query = query +" and created BETWEEN "+startMillis +" AND "+endMillis;

//log.error("query :"+query);


return query;
